INSERT INTO public.dokkai_passages (level_id, order_index, title, text_content, content_json, vocab_notes, questions, is_premium) VALUES
(2, 6, '電車の乗り方 — Cara Naik Kereta',
 '日本では、電車が一番便利な乗り物です。私は毎日電車で学校に通っています。まず、駅で切符を買うか、ICカードを使います。改札を通って、ホームへ行きます。電車が来たら、降りる人を先に待ちます。朝のラッシュアワーは、とても込んでいます。席が空いていたら、座ることができます。電車の中では、静かにしなければなりません。電話で話すのはマナー違反です。降りる駅に着いたら、忘れ物に気をつけます。時々、電車が遅れることもあります。でも、日本の電車はだいたい時間に正確です。慣れると、電車の旅はとても楽しいです。',
 '[
   {"jp":"日本では、電車が一番便利な乗り物です。","furigana":"にほんでは、でんしゃがいちばんべんりなのりものです。","romaji":"Nihon de wa, densha ga ichiban benri na norimono desu.","id":"Di Jepang, kereta adalah alat transportasi paling praktis."},
   {"jp":"私は毎日電車で学校に通っています。","furigana":"わたしはまいにちでんしゃでがっこうにかよっています。","romaji":"Watashi wa mainichi densha de gakkou ni kayotte imasu.","id":"Aku setiap hari pergi ke sekolah naik kereta."},
   {"jp":"まず、駅で切符を買うか、ICカードを使います。","furigana":"まず、えきできっぷをかうか、アイシーカードをつかいます。","romaji":"Mazu, eki de kippu o kau ka, ai-shii-kaado o tsukaimasu.","id":"Pertama, beli tiket di stasiun atau gunakan kartu IC."},
   {"jp":"改札を通って、ホームへ行きます。","furigana":"かいさつをとおって、ホームへいきます。","romaji":"Kaisatsu o tootte, hoomu e ikimasu.","id":"Lewati gerbang tiket lalu pergi ke peron."},
   {"jp":"電車が来たら、降りる人を先に待ちます。","furigana":"でんしゃがきたら、おりるひとをさきにまちます。","romaji":"Densha ga kitara, oriru hito o saki ni machimasu.","id":"Kalau kereta datang, tunggu dulu orang yang turun."},
   {"jp":"朝のラッシュアワーは、とても込んでいます。","furigana":"あさのラッシュアワーは、とてもこんでいます。","romaji":"Asa no rasshu awaa wa, totemo konde imasu.","id":"Jam sibuk pagi sangat padat."},
   {"jp":"席が空いていたら、座ることができます。","furigana":"せきがあいていたら、すわることができます。","romaji":"Seki ga aite itara, suwaru koto ga dekimasu.","id":"Kalau ada kursi kosong, kita bisa duduk."},
   {"jp":"電車の中では、静かにしなければなりません。","furigana":"でんしゃのなかでは、しずかにしなければなりません。","romaji":"Densha no naka de wa, shizuka ni shinakereba narimasen.","id":"Di dalam kereta kita harus tenang."},
   {"jp":"電話で話すのはマナー違反です。","furigana":"でんわではなすのはマナーいはんです。","romaji":"Denwa de hanasu no wa manaa ihan desu.","id":"Berbicara di telepon melanggar etika."},
   {"jp":"降りる駅に着いたら、忘れ物に気をつけます。","furigana":"おりるえきについたら、わすれものにきをつけます。","romaji":"Oriru eki ni tsuitara, wasuremono ni ki o tsukemasu.","id":"Saat tiba di stasiun tujuan, hati-hati jangan ada barang tertinggal."},
   {"jp":"時々、電車が遅れることもあります。","furigana":"ときどき、でんしゃがおくれることもあります。","romaji":"Tokidoki, densha ga okureru koto mo arimasu.","id":"Kadang kereta juga terlambat."},
   {"jp":"でも、日本の電車はだいたい時間に正確です。","furigana":"でも、にほんのでんしゃはだいたいじかんにせいかくです。","romaji":"Demo, nihon no densha wa daitai jikan ni seikaku desu.","id":"Tapi kereta Jepang umumnya tepat waktu."},
   {"jp":"慣れると、電車の旅はとても楽しいです。","furigana":"なれると、でんしゃのたびはとてもたのしいです。","romaji":"Nareru to, densha no tabi wa totemo tanoshii desu.","id":"Setelah terbiasa, perjalanan kereta sangat menyenangkan."}
 ]'::jsonb,
 '[
   {"word":"電車","reading":"でんしゃ","romaji":"densha","meaning":"kereta listrik"},
   {"word":"便利","reading":"べんり","romaji":"benri","meaning":"praktis"},
   {"word":"乗り物","reading":"のりもの","romaji":"norimono","meaning":"kendaraan"},
   {"word":"通う","reading":"かよう","romaji":"kayou","meaning":"pergi rutin/bolak-balik"},
   {"word":"切符","reading":"きっぷ","romaji":"kippu","meaning":"tiket"},
   {"word":"改札","reading":"かいさつ","romaji":"kaisatsu","meaning":"gerbang tiket"},
   {"word":"ホーム","reading":"ホーム","romaji":"hoomu","meaning":"peron"},
   {"word":"降りる","reading":"おりる","romaji":"oriru","meaning":"turun"},
   {"word":"込む","reading":"こむ","romaji":"komu","meaning":"padat/ramai"},
   {"word":"席","reading":"せき","romaji":"seki","meaning":"kursi"},
   {"word":"空く","reading":"あく","romaji":"aku","meaning":"kosong"},
   {"word":"静か","reading":"しずか","romaji":"shizuka","meaning":"tenang"},
   {"word":"マナー違反","reading":"マナーいはん","romaji":"manaa ihan","meaning":"pelanggaran etika"},
   {"word":"忘れ物","reading":"わすれもの","romaji":"wasuremono","meaning":"barang tertinggal"},
   {"word":"遅れる","reading":"おくれる","romaji":"okureru","meaning":"terlambat"}
 ]'::jsonb,
 '[
   {"q":"Di Jepang, transportasi paling praktis adalah?","options":["Bus","Kereta","Taksi","Sepeda"],"answer":1,"explanation":"「電車が一番便利な乗り物」 = kereta paling praktis."},
   {"q":"Apa yang dilakukan dulu di stasiun?","options":["Cari kursi","Beli tiket atau pakai kartu IC","Menelepon","Makan"],"answer":1,"explanation":"「切符を買うか、ICカードを使います」."},
   {"q":"Saat kereta datang, apa yang dilakukan dulu?","options":["Langsung masuk","Tunggu orang yang turun dulu","Berlari","Duduk"],"answer":1,"explanation":"「降りる人を先に待ちます」."},
   {"q":"Bagaimana jam sibuk pagi?","options":["Sepi","Sangat padat","Biasa saja","Tutup"],"answer":1,"explanation":"「とても込んでいます」 = sangat padat."},
   {"q":"Apa yang melanggar etika di kereta?","options":["Duduk","Membaca","Bicara di telepon","Tidur"],"answer":2,"explanation":"「電話で話すのはマナー違反」."},
   {"q":"Bagaimana ketepatan waktu kereta Jepang?","options":["Sering telat","Umumnya tepat waktu","Tidak ada jadwal","Selalu telat"],"answer":1,"explanation":"「だいたい時間に正確」 = umumnya tepat waktu."}
 ]'::jsonb,
 false),
(2, 7, '日本のコンビニ — Konbini Jepang',
 '日本のコンビニはとても便利です。コンビニは二十四時間開いています。食べ物や飲み物だけでなく、雑誌も売っています。おにぎりやお弁当は、いつも新鮮です。お弁当は電子レンジで温めてくれます。コンビニで公共料金を払うこともできます。荷物を送ったり、受け取ったりできます。ATMもあるので、お金をおろせます。トイレを貸してくれる店も多いです。店員さんはいつも丁寧で親切です。私はよく帰り道にコンビニに寄ります。コンビニは私たちの生活に欠かせません。',
 '[
   {"jp":"日本のコンビニはとても便利です。","furigana":"にほんのコンビニはとてもべんりです。","romaji":"Nihon no konbini wa totemo benri desu.","id":"Konbini Jepang sangat praktis."},
   {"jp":"コンビニは二十四時間開いています。","furigana":"コンビニはにじゅうよじかんあいています。","romaji":"Konbini wa nijuuyo-jikan aite imasu.","id":"Konbini buka 24 jam."},
   {"jp":"食べ物や飲み物だけでなく、雑誌も売っています。","furigana":"たべものやのみものだけでなく、ざっしもうっています。","romaji":"Tabemono ya nomimono dake de naku, zasshi mo utte imasu.","id":"Tidak hanya makanan dan minuman, majalah pun dijual."},
   {"jp":"おにぎりやお弁当は、いつも新鮮です。","furigana":"おにぎりやおべんとうは、いつもしんせんです。","romaji":"Onigiri ya obentou wa, itsumo shinsen desu.","id":"Onigiri dan bento selalu segar."},
   {"jp":"お弁当は電子レンジで温めてくれます。","furigana":"おべんとうはでんしレンジであたためてくれます。","romaji":"Obentou wa denshi renji de atatamete kuremasu.","id":"Bento dihangatkan dengan microwave untuk kita."},
   {"jp":"コンビニで公共料金を払うこともできます。","furigana":"コンビニでこうきょうりょうきんをはらうこともできます。","romaji":"Konbini de koukyou ryoukin o harau koto mo dekimasu.","id":"Di konbini kita juga bisa membayar tagihan umum."},
   {"jp":"荷物を送ったり、受け取ったりできます。","furigana":"にもつをおくったり、うけとったりできます。","romaji":"Nimotsu o okuttari, uketottari dekimasu.","id":"Kita bisa mengirim dan menerima paket."},
   {"jp":"ATMもあるので、お金をおろせます。","furigana":"エーティーエムもあるので、おかねをおろせます。","romaji":"ATM mo aru node, okane o orosemasu.","id":"Karena ada ATM juga, kita bisa menarik uang."},
   {"jp":"トイレを貸してくれる店も多いです。","furigana":"トイレをかしてくれるみせもおおいです。","romaji":"Toire o kashite kureru mise mo ooi desu.","id":"Banyak juga toko yang meminjamkan toilet."},
   {"jp":"店員さんはいつも丁寧で親切です。","furigana":"てんいんさんはいつもていねいでしんせつです。","romaji":"Ten-in-san wa itsumo teinei de shinsetsu desu.","id":"Pelayan toko selalu sopan dan ramah."},
   {"jp":"私はよく帰り道にコンビニに寄ります。","furigana":"わたしはよくかえりみちにコンビニによります。","romaji":"Watashi wa yoku kaerimichi ni konbini ni yorimasu.","id":"Aku sering mampir ke konbini saat perjalanan pulang."},
   {"jp":"コンビニは私たちの生活に欠かせません。","furigana":"コンビニはわたしたちのせいかつにかかせません。","romaji":"Konbini wa watashitachi no seikatsu ni kakasemasen.","id":"Konbini tak tergantikan dalam kehidupan kita."}
 ]'::jsonb,
 '[
   {"word":"コンビニ","reading":"コンビニ","romaji":"konbini","meaning":"minimarket 24 jam"},
   {"word":"便利","reading":"べんり","romaji":"benri","meaning":"praktis"},
   {"word":"二十四時間","reading":"にじゅうよじかん","romaji":"nijuuyo-jikan","meaning":"24 jam"},
   {"word":"雑誌","reading":"ざっし","romaji":"zasshi","meaning":"majalah"},
   {"word":"売る","reading":"うる","romaji":"uru","meaning":"menjual"},
   {"word":"お弁当","reading":"おべんとう","romaji":"obentou","meaning":"bekal/bento"},
   {"word":"新鮮","reading":"しんせん","romaji":"shinsen","meaning":"segar"},
   {"word":"温める","reading":"あたためる","romaji":"atatameru","meaning":"menghangatkan"},
   {"word":"公共料金","reading":"こうきょうりょうきん","romaji":"koukyou ryoukin","meaning":"tagihan umum (listrik dll.)"},
   {"word":"払う","reading":"はらう","romaji":"harau","meaning":"membayar"},
   {"word":"荷物","reading":"にもつ","romaji":"nimotsu","meaning":"paket/barang"},
   {"word":"受け取る","reading":"うけとる","romaji":"uketoru","meaning":"menerima"},
   {"word":"店員","reading":"てんいん","romaji":"ten-in","meaning":"pelayan toko"},
   {"word":"丁寧","reading":"ていねい","romaji":"teinei","meaning":"sopan/cermat"},
   {"word":"欠かせない","reading":"かかせない","romaji":"kakasenai","meaning":"tak tergantikan"}
 ]'::jsonb,
 '[
   {"q":"Konbini buka berapa lama?","options":["12 jam","24 jam","Siang saja","Sampai malam"],"answer":1,"explanation":"「二十四時間開いています」 = buka 24 jam."},
   {"q":"Selain makanan dan minuman, apa yang dijual?","options":["Baju","Majalah","Sepatu","Obat"],"answer":1,"explanation":"「雑誌も売っています」 = majalah juga dijual."},
   {"q":"Bento dihangatkan dengan apa?","options":["Oven","Microwave","Kompor","Air panas"],"answer":1,"explanation":"「電子レンジで温めて」 = dengan microwave."},
   {"q":"Apa yang bisa dibayar di konbini?","options":["Pajak mobil","Tagihan umum","SPP","Sewa rumah"],"answer":1,"explanation":"「公共料金を払うこともできます」."},
   {"q":"Bagaimana pelayan tokonya?","options":["Cuek","Sopan dan ramah","Galak","Lambat"],"answer":1,"explanation":"「丁寧で親切」 = sopan dan ramah."},
   {"q":"Kapan penulis sering mampir ke konbini?","options":["Pagi hari","Saat perjalanan pulang","Tengah malam","Saat libur"],"answer":1,"explanation":"「帰り道にコンビニに寄ります」."}
 ]'::jsonb,
 false),
(2, 8, 'お祭り — Festival Matsuri',
 '夏になると、日本では色々なお祭りがあります。先週、私は友だちと町のお祭りに行きました。たくさんの人が浴衣を着ていました。道の両側に屋台がたくさん並んでいました。私はたこ焼きとかき氷を食べました。金魚すくいもやってみました。太鼓の音が町中に響いていました。夜になると、大きな花火が上がりました。花火はとてもきれいで、みんな空を見上げました。お祭りは日本の大切な伝統文化です。私はまた来年も行きたいと思います。お祭りの思い出は一生忘れません。',
 '[
   {"jp":"夏になると、日本では色々なお祭りがあります。","furigana":"なつになると、にほんではいろいろなおまつりがあります。","romaji":"Natsu ni naru to, nihon de wa iroiro na omatsuri ga arimasu.","id":"Saat musim panas, di Jepang ada bermacam festival."},
   {"jp":"先週、私は友だちと町のお祭りに行きました。","furigana":"せんしゅう、わたしはともだちとまちのおまつりにいきました。","romaji":"Senshuu, watashi wa tomodachi to machi no omatsuri ni ikimashita.","id":"Minggu lalu aku pergi ke festival kota dengan teman."},
   {"jp":"たくさんの人が浴衣を着ていました。","furigana":"たくさんのひとがゆかたをきていました。","romaji":"Takusan no hito ga yukata o kite imashita.","id":"Banyak orang mengenakan yukata."},
   {"jp":"道の両側に屋台がたくさん並んでいました。","furigana":"みちのりょうがわにやたいがたくさんならんでいました。","romaji":"Michi no ryougawa ni yatai ga takusan narande imashita.","id":"Di kedua sisi jalan berjajar banyak kios."},
   {"jp":"私はたこ焼きとかき氷を食べました。","furigana":"わたしはたこやきとかきごおりをたべました。","romaji":"Watashi wa takoyaki to kakigoori o tabemashita.","id":"Aku makan takoyaki dan es serut."},
   {"jp":"金魚すくいもやってみました。","furigana":"きんぎょすくいもやってみました。","romaji":"Kingyo sukui mo yatte mimashita.","id":"Aku juga mencoba menangkap ikan mas."},
   {"jp":"太鼓の音が町中に響いていました。","furigana":"たいこのおとがまちじゅうにひびいていました。","romaji":"Taiko no oto ga machijuu ni hibiite imashita.","id":"Suara taiko bergema ke seluruh kota."},
   {"jp":"夜になると、大きな花火が上がりました。","furigana":"よるになると、おおきなはなびがあがりました。","romaji":"Yoru ni naru to, ooki na hanabi ga agarimashita.","id":"Saat malam, kembang api besar diluncurkan."},
   {"jp":"花火はとてもきれいで、みんな空を見上げました。","furigana":"はなびはとてもきれいで、みんなそらをみあげました。","romaji":"Hanabi wa totemo kirei de, minna sora o miagemashita.","id":"Kembang apinya sangat indah, semua mendongak ke langit."},
   {"jp":"お祭りは日本の大切な伝統文化です。","furigana":"おまつりはにほんのたいせつなでんとうぶんかです。","romaji":"Omatsuri wa nihon no taisetsu na dentou bunka desu.","id":"Festival adalah budaya tradisional Jepang yang penting."},
   {"jp":"私はまた来年も行きたいと思います。","furigana":"わたしはまたらいねんもいきたいとおもいます。","romaji":"Watashi wa mata rainen mo ikitai to omoimasu.","id":"Aku ingin pergi lagi tahun depan."},
   {"jp":"お祭りの思い出は一生忘れません。","furigana":"おまつりのおもいではいっしょうわすれません。","romaji":"Omatsuri no omoide wa isshou wasuremasen.","id":"Kenangan festival ini takkan kulupakan seumur hidup."}
 ]'::jsonb,
 '[
   {"word":"お祭り","reading":"おまつり","romaji":"omatsuri","meaning":"festival"},
   {"word":"浴衣","reading":"ゆかた","romaji":"yukata","meaning":"yukata (kimono musim panas)"},
   {"word":"屋台","reading":"やたい","romaji":"yatai","meaning":"kios/warung tenda"},
   {"word":"並ぶ","reading":"ならぶ","romaji":"narabu","meaning":"berjajar"},
   {"word":"たこ焼き","reading":"たこやき","romaji":"takoyaki","meaning":"takoyaki"},
   {"word":"かき氷","reading":"かきごおり","romaji":"kakigoori","meaning":"es serut"},
   {"word":"金魚すくい","reading":"きんぎょすくい","romaji":"kingyo sukui","meaning":"permainan tangkap ikan mas"},
   {"word":"太鼓","reading":"たいこ","romaji":"taiko","meaning":"genderang taiko"},
   {"word":"響く","reading":"ひびく","romaji":"hibiku","meaning":"bergema"},
   {"word":"花火","reading":"はなび","romaji":"hanabi","meaning":"kembang api"},
   {"word":"上がる","reading":"あがる","romaji":"agaru","meaning":"naik/diluncurkan"},
   {"word":"見上げる","reading":"みあげる","romaji":"miageru","meaning":"mendongak"},
   {"word":"伝統文化","reading":"でんとうぶんか","romaji":"dentou bunka","meaning":"budaya tradisional"},
   {"word":"思い出","reading":"おもいで","romaji":"omoide","meaning":"kenangan"},
   {"word":"一生","reading":"いっしょう","romaji":"isshou","meaning":"seumur hidup"}
 ]'::jsonb,
 '[
   {"q":"Kapan banyak festival diadakan di Jepang?","options":["Musim dingin","Musim panas","Musim semi","Musim gugur"],"answer":1,"explanation":"「夏になると…お祭りがあります」."},
   {"q":"Apa yang dikenakan banyak orang?","options":["Kimono formal","Yukata","Jas","Seragam"],"answer":1,"explanation":"「浴衣を着ていました」 = mengenakan yukata."},
   {"q":"Apa yang penulis makan?","options":["Ramen","Takoyaki dan es serut","Sushi","Onigiri"],"answer":1,"explanation":"「たこ焼きとかき氷を食べました」."},
   {"q":"Suara apa yang bergema ke seluruh kota?","options":["Lonceng","Taiko","Musik pop","Peluit"],"answer":1,"explanation":"「太鼓の音が…響いていました」."},
   {"q":"Apa yang terjadi saat malam?","options":["Hujan","Kembang api besar diluncurkan","Festival selesai","Parade"],"answer":1,"explanation":"「大きな花火が上がりました」."},
   {"q":"Bagaimana pendapat penulis tentang festival?","options":["Membosankan","Budaya tradisional yang penting","Terlalu ramai","Mahal"],"answer":1,"explanation":"「大切な伝統文化です」."}
 ]'::jsonb,
 false),
(2, 9, '引っ越し — Pindah Rumah',
 '来月、私は新しいアパートに引っ越します。今の部屋は狭くて、少し不便でした。新しいアパートは駅から近くて、便利です。引っ越しの前に、荷物を箱に詰めます。いらない物は捨てるか、友だちにあげます。引っ越しの日は、トラックで荷物を運びます。友だちが手伝いに来てくれました。大きな家具を運ぶのは大変でした。新しい部屋を掃除してから、荷物を片付けました。引っ越しの後で、近所の人に挨拶しました。新しい生活が始まって、とても楽しみです。早く新しい町に慣れたいです。',
 '[
   {"jp":"来月、私は新しいアパートに引っ越します。","furigana":"らいげつ、わたしはあたらしいアパートにひっこします。","romaji":"Raigetsu, watashi wa atarashii apaato ni hikkoshimasu.","id":"Bulan depan aku pindah ke apartemen baru."},
   {"jp":"今の部屋は狭くて、少し不便でした。","furigana":"いまのへやはせまくて、すこしふべんでした。","romaji":"Ima no heya wa semakute, sukoshi fuben deshita.","id":"Kamarku sekarang sempit dan agak tidak nyaman."},
   {"jp":"新しいアパートは駅から近くて、便利です。","furigana":"あたらしいアパートはえきからちかくて、べんりです。","romaji":"Atarashii apaato wa eki kara chikakute, benri desu.","id":"Apartemen baru dekat stasiun dan praktis."},
   {"jp":"引っ越しの前に、荷物を箱に詰めます。","furigana":"ひっこしのまえに、にもつをはこにつめます。","romaji":"Hikkoshi no mae ni, nimotsu o hako ni tsumemasu.","id":"Sebelum pindah, aku mengemas barang ke dalam kardus."},
   {"jp":"いらない物は捨てるか、友だちにあげます。","furigana":"いらないものはすてるか、ともだちにあげます。","romaji":"Iranai mono wa suteru ka, tomodachi ni agemasu.","id":"Barang yang tidak perlu dibuang atau diberikan ke teman."},
   {"jp":"引っ越しの日は、トラックで荷物を運びます。","furigana":"ひっこしのひは、トラックでにもつをはこびます。","romaji":"Hikkoshi no hi wa, torakku de nimotsu o hakobimasu.","id":"Pada hari pindah, barang diangkut dengan truk."},
   {"jp":"友だちが手伝いに来てくれました。","furigana":"ともだちがてつだいにきてくれました。","romaji":"Tomodachi ga tetsudai ni kite kuremashita.","id":"Teman datang untuk membantu."},
