   {"q":"Ke mana penulis pergi untuk pertama kali?","options":["Osaka","Tokyo","Kyoto","Nagoya"],"answer":1,"explanation":"「初めて東京に行きました」."},
   {"q":"Kenapa stasiunnya membingungkan?","options":["Gelap","Besar dan banyak pintu keluar","Sepi","Tutup"],"answer":1,"explanation":"「大きくて、出口がたくさん」."},
   {"q":"Apa yang dilakukan penulis saat tersesat?","options":["Menangis","Bertanya pada orang","Pulang","Diam"],"answer":1,"explanation":"「近くの人に道を聞きました」."},
   {"q":"Bagaimana petunjuk jalannya?","options":["Belok kiri","Lurus lalu belok kanan di tikungan kedua","Naik taksi","Putar balik"],"answer":1,"explanation":"「まっすぐ行って、二つ目の角を右に」."},
   {"q":"Apa yang juga berguna?","options":["Kompas","Aplikasi peta di ponsel","Buku","Papan petunjuk"],"answer":1,"explanation":"「地図アプリも役に立ちました」."},
   {"q":"Menurut penulis, saat tersesat yang terbaik adalah?","options":["Pakai peta","Bertanya pada orang","Menunggu","Menelepon"],"answer":1,"explanation":"「人に聞くのが一番」."}
 ]'::jsonb,
 false),
(2, 13, '携帯電話 — Telepon Genggam',
 '今、ほとんどの人が携帯電話を持っています。携帯電話はとても便利な道具です。電話やメールだけでなく、写真も撮れます。地図を見たり、ニュースを読んだりできます。私はよく友だちとメッセージを送り合います。でも、使いすぎると目が疲れます。歩きながらスマホを使うのは危ないです。電車の中では、マナーモードにします。寝る前にスマホを見ると、よく眠れません。だから、私は夜十時以降は使わないようにしています。携帯電話は便利ですが、使い方が大切です。上手に使えば、生活がもっと豊かになります。',
 '[
   {"jp":"今、ほとんどの人が携帯電話を持っています。","furigana":"いま、ほとんどのひとがけいたいでんわをもっています。","romaji":"Ima, hotondo no hito ga keitai denwa o motte imasu.","id":"Sekarang hampir semua orang punya ponsel."},
   {"jp":"携帯電話はとても便利な道具です。","furigana":"けいたいでんわはとてもべんりなどうぐです。","romaji":"Keitai denwa wa totemo benri na dougu desu.","id":"Ponsel adalah alat yang sangat praktis."},
   {"jp":"電話やメールだけでなく、写真も撮れます。","furigana":"でんわやメールだけでなく、しゃしんもとれます。","romaji":"Denwa ya meeru dake de naku, shashin mo toremasu.","id":"Tidak hanya telepon dan email, kita juga bisa memotret."},
   {"jp":"地図を見たり、ニュースを読んだりできます。","furigana":"ちずをみたり、ニュースをよんだりできます。","romaji":"Chizu o mitari, nyuusu o yondari dekimasu.","id":"Kita bisa melihat peta dan membaca berita."},
   {"jp":"私はよく友だちとメッセージを送り合います。","furigana":"わたしはよくともだちとメッセージをおくりあいます。","romaji":"Watashi wa yoku tomodachi to messeeji o okuri aimasu.","id":"Aku sering bertukar pesan dengan teman."},
   {"jp":"でも、使いすぎると目が疲れます。","furigana":"でも、つかいすぎるとめがつかれます。","romaji":"Demo, tsukai sugiru to me ga tsukaremasu.","id":"Tapi kalau berlebihan, mata jadi lelah."},
   {"jp":"歩きながらスマホを使うのは危ないです。","furigana":"あるきながらスマホをつかうのはあぶないです。","romaji":"Aruki nagara sumaho o tsukau no wa abunai desu.","id":"Memakai ponsel sambil berjalan itu berbahaya."},
   {"jp":"電車の中では、マナーモードにします。","furigana":"でんしゃのなかでは、マナーモードにします。","romaji":"Densha no naka de wa, manaa moodo ni shimasu.","id":"Di dalam kereta, aku setel ke mode senyap."},
   {"jp":"寝る前にスマホを見ると、よく眠れません。","furigana":"ねるまえにスマホをみると、よくねむれません。","romaji":"Neru mae ni sumaho o miru to, yoku nemuremasen.","id":"Kalau melihat ponsel sebelum tidur, sulit tidur nyenyak."},
   {"jp":"だから、私は夜十時以降は使わないようにしています。","furigana":"だから、わたしはよるじゅうじいこうはつかわないようにしています。","romaji":"Dakara, watashi wa yoru juuji ikou wa tsukawanai you ni shite imasu.","id":"Karena itu, aku berusaha tidak memakainya setelah jam sepuluh malam."},
   {"jp":"携帯電話は便利ですが、使い方が大切です。","furigana":"けいたいでんわはべんりですが、つかいかたがたいせつです。","romaji":"Keitai denwa wa benri desu ga, tsukaikata ga taisetsu desu.","id":"Ponsel praktis, tapi cara memakainya penting."},
   {"jp":"上手に使えば、生活がもっと豊かになります。","furigana":"じょうずにつかえば、せいかつがもっとゆたかになります。","romaji":"Jouzu ni tsukaeba, seikatsu ga motto yutaka ni narimasu.","id":"Kalau dipakai dengan bijak, hidup jadi lebih kaya."}
 ]'::jsonb,
 '[
   {"word":"携帯電話","reading":"けいたいでんわ","romaji":"keitai denwa","meaning":"ponsel"},
   {"word":"道具","reading":"どうぐ","romaji":"dougu","meaning":"alat"},
   {"word":"撮る","reading":"とる","romaji":"toru","meaning":"memotret/mengambil (foto)"},
   {"word":"メール","reading":"メール","romaji":"meeru","meaning":"email"},
   {"word":"メッセージ","reading":"メッセージ","romaji":"messeeji","meaning":"pesan"},
   {"word":"送る","reading":"おくる","romaji":"okuru","meaning":"mengirim"},
   {"word":"使いすぎる","reading":"つかいすぎる","romaji":"tsukai sugiru","meaning":"memakai berlebihan"},
   {"word":"疲れる","reading":"つかれる","romaji":"tsukareru","meaning":"lelah"},
   {"word":"危ない","reading":"あぶない","romaji":"abunai","meaning":"berbahaya"},
   {"word":"マナーモード","reading":"マナーモード","romaji":"manaa moodo","meaning":"mode senyap"},
   {"word":"眠る","reading":"ねむる","romaji":"nemuru","meaning":"tidur/terlelap"},
   {"word":"以降","reading":"いこう","romaji":"ikou","meaning":"setelah/sesudah"},
   {"word":"使い方","reading":"つかいかた","romaji":"tsukaikata","meaning":"cara pakai"},
   {"word":"上手に","reading":"じょうずに","romaji":"jouzu ni","meaning":"dengan mahir/bijak"},
   {"word":"豊か","reading":"ゆたか","romaji":"yutaka","meaning":"kaya/melimpah"}
 ]'::jsonb,
 '[
   {"q":"Sekarang siapa yang punya ponsel?","options":["Sedikit orang","Hampir semua orang","Hanya anak muda","Hanya pekerja"],"answer":1,"explanation":"「ほとんどの人が…持っています」."},
   {"q":"Selain telepon dan email, ponsel bisa apa?","options":["Memasak","Memotret","Mencuci","Terbang"],"answer":1,"explanation":"「写真も撮れます」 = bisa memotret."},
   {"q":"Apa akibat memakai ponsel berlebihan?","options":["Mata lelah","Lapar","Kebal","Lebih pintar"],"answer":0,"explanation":"「使いすぎると目が疲れます」."},
   {"q":"Apa yang berbahaya menurut penulis?","options":["Mengisi daya","Memakai ponsel sambil berjalan","Menelepon","Memotret"],"answer":1,"explanation":"「歩きながらスマホを使うのは危ない」."},
   {"q":"Kenapa tidak melihat ponsel sebelum tidur?","options":["Boros baterai","Sulit tidur nyenyak","Mata buta","Lupa waktu"],"answer":1,"explanation":"「よく眠れません」 = sulit tidur nyenyak."},
   {"q":"Setelah jam berapa penulis berusaha tidak memakai ponsel?","options":["Jam 8","Jam 9","Jam 10 malam","Jam 11"],"answer":2,"explanation":"「夜十時以降は使わないように」."}
 ]'::jsonb,
 false),
(2, 14, '冬の準備 — Persiapan Musim Dingin',
 '十一月になると、だんだん寒くなってきます。冬が来る前に、いろいろな準備をします。まず、厚いコートやセーターを出します。部屋には暖房やこたつを用意します。寒い日は、温かい飲み物が欲しくなります。北の地方では、雪がたくさん降ります。雪が降ると、道が滑りやすくなります。だから、滑らない靴を履きます。冬は風邪をひきやすいので、気をつけます。手洗いとうがいを忘れないようにしています。冬は寒いですが、温泉に入るのが楽しみです。しっかり準備をすれば、冬も快適に過ごせます。',
 '[
   {"jp":"十一月になると、だんだん寒くなってきます。","furigana":"じゅういちがつになると、だんだんさむくなってきます。","romaji":"Juuichigatsu ni naru to, dandan samuku natte kimasu.","id":"Begitu masuk November, lama-lama jadi dingin."},
   {"jp":"冬が来る前に、いろいろな準備をします。","furigana":"ふゆがくるまえに、いろいろなじゅんびをします。","romaji":"Fuyu ga kuru mae ni, iroiro na junbi o shimasu.","id":"Sebelum musim dingin datang, aku melakukan berbagai persiapan."},
   {"jp":"まず、厚いコートやセーターを出します。","furigana":"まず、あついコートやセーターをだします。","romaji":"Mazu, atsui kooto ya seetaa o dashimasu.","id":"Pertama, aku mengeluarkan mantel tebal dan sweter."},
   {"jp":"部屋には暖房やこたつを用意します。","furigana":"へやにはだんぼうやこたつをよういします。","romaji":"Heya ni wa danbou ya kotatsu o youi shimasu.","id":"Di kamar aku menyiapkan pemanas dan kotatsu."},
   {"jp":"寒い日は、温かい飲み物が欲しくなります。","furigana":"さむいひは、あたたかいのみものがほしくなります。","romaji":"Samui hi wa, atatakai nomimono ga hoshiku narimasu.","id":"Di hari dingin, jadi ingin minuman hangat."},
   {"jp":"北の地方では、雪がたくさん降ります。","furigana":"きたのちほうでは、ゆきがたくさんふります。","romaji":"Kita no chihou de wa, yuki ga takusan furimasu.","id":"Di daerah utara, salju turun banyak."},
   {"jp":"雪が降ると、道が滑りやすくなります。","furigana":"ゆきがふると、みちがすべりやすくなります。","romaji":"Yuki ga furu to, michi ga suberiyasuku narimasu.","id":"Kalau salju turun, jalan jadi mudah licin."},
   {"jp":"だから、滑らない靴を履きます。","furigana":"だから、すべらないくつをはきます。","romaji":"Dakara, suberanai kutsu o hakimasu.","id":"Karena itu, aku memakai sepatu anti licin."},
   {"jp":"冬は風邪をひきやすいので、気をつけます。","furigana":"ふゆはかぜをひきやすいので、きをつけます。","romaji":"Fuyu wa kaze o hikiyasui node, ki o tsukemasu.","id":"Musim dingin mudah masuk angin, jadi aku berhati-hati."},
   {"jp":"手洗いとうがいを忘れないようにしています。","furigana":"てあらいとうがいをわすれないようにしています。","romaji":"Tearai to ugai o wasurenai you ni shite imasu.","id":"Aku berusaha tidak lupa cuci tangan dan berkumur."},
   {"jp":"冬は寒いですが、温泉に入るのが楽しみです。","furigana":"ふゆはさむいですが、おんせんにはいるのがたのしみです。","romaji":"Fuyu wa samui desu ga, onsen ni hairu no ga tanoshimi desu.","id":"Musim dingin memang dingin, tapi aku menantikan berendam di onsen."},
   {"jp":"しっかり準備をすれば、冬も快適に過ごせます。","furigana":"しっかりじゅんびをすれば、ふゆもかいてきにすごせます。","romaji":"Shikkari junbi o sureba, fuyu mo kaiteki ni sugosemasu.","id":"Kalau persiapan matang, musim dingin pun bisa dilewati dengan nyaman."}
 ]'::jsonb,
 '[
   {"word":"準備","reading":"じゅんび","romaji":"junbi","meaning":"persiapan"},
   {"word":"だんだん","reading":"だんだん","romaji":"dandan","meaning":"lama-lama/berangsur"},
   {"word":"厚い","reading":"あつい","romaji":"atsui","meaning":"tebal"},
   {"word":"コート","reading":"コート","romaji":"kooto","meaning":"mantel"},
   {"word":"暖房","reading":"だんぼう","romaji":"danbou","meaning":"pemanas ruangan"},
   {"word":"こたつ","reading":"こたつ","romaji":"kotatsu","meaning":"kotatsu (meja penghangat)"},
   {"word":"用意","reading":"ようい","romaji":"youi","meaning":"menyiapkan"},
   {"word":"地方","reading":"ちほう","romaji":"chihou","meaning":"daerah/wilayah"},
   {"word":"滑る","reading":"すべる","romaji":"suberu","meaning":"licin/tergelincir"},
   {"word":"履く","reading":"はく","romaji":"haku","meaning":"memakai (alas kaki)"},
   {"word":"風邪をひく","reading":"かぜをひく","romaji":"kaze o hiku","meaning":"masuk angin/pilek"},
   {"word":"うがい","reading":"うがい","romaji":"ugai","meaning":"berkumur"},
   {"word":"温泉","reading":"おんせん","romaji":"onsen","meaning":"pemandian air panas"},
   {"word":"快適","reading":"かいてき","romaji":"kaiteki","meaning":"nyaman"},
   {"word":"過ごす","reading":"すごす","romaji":"sugosu","meaning":"melewati waktu"}
 ]'::jsonb,
 '[
   {"q":"Bulan apa mulai terasa dingin?","options":["September","Oktober","November","Desember"],"answer":2,"explanation":"「十一月になると…寒くなってきます」."},
   {"q":"Apa yang dikeluarkan lebih dulu?","options":["Kipas","Mantel tebal dan sweter","Payung","Topi pantai"],"answer":1,"explanation":"「厚いコートやセーターを出します」."},
   {"q":"Apa yang disiapkan di kamar?","options":["AC","Pemanas dan kotatsu","Kulkas","Kipas angin"],"answer":1,"explanation":"「暖房やこたつを用意します」."},
   {"q":"Kenapa memakai sepatu anti licin?","options":["Agar keren","Jalan mudah licin saat bersalju","Agar hangat","Karena murah"],"answer":1,"explanation":"「道が滑りやすくなります」."},
   {"q":"Apa yang dilakukan agar tidak masuk angin?","options":["Olahraga","Cuci tangan dan berkumur","Banyak tidur","Minum obat"],"answer":1,"explanation":"「手洗いとうがいを忘れないように」."},
   {"q":"Apa yang dinantikan penulis di musim dingin?","options":["Main salju","Berendam di onsen","Liburan","Tahun baru"],"answer":1,"explanation":"「温泉に入るのが楽しみ」."}
 ]'::jsonb,
 false),
(2, 15, 'ボランティア — Kegiatan Sukarela',
 '先月、私は初めてボランティア活動に参加しました。友だちに誘われて、海の掃除をしました。朝早く集まって、ゴミを拾いました。海にはプラスチックのゴミがたくさんありました。ゴミは海の動物にとって危険です。みんなで協力して、たくさんのゴミを集めました。三時間後、海はとてもきれいになりました。体は疲れましたが、心は気持ちよかったです。自分の行動が役に立って、嬉しかったです。環境を守ることはとても大切だと思いました。これからも、時々ボランティアに参加したいです。小さな行動が、大きな変化につながると信じています。',
 '[
   {"jp":"先月、私は初めてボランティア活動に参加しました。","furigana":"せんげつ、わたしははじめてボランティアかつどうにさんかしました。","romaji":"Sengetsu, watashi wa hajimete borantia katsudou ni sanka shimashita.","id":"Bulan lalu aku ikut kegiatan sukarela untuk pertama kali."},
   {"jp":"友だちに誘われて、海の掃除をしました。","furigana":"ともだちにさそわれて、うみのそうじをしました。","romaji":"Tomodachi ni sasowarete, umi no souji o shimashita.","id":"Diajak teman, aku membersihkan pantai."},
   {"jp":"朝早く集まって、ゴミを拾いました。","furigana":"あさはやくあつまって、ゴミをひろいました。","romaji":"Asa hayaku atsumatte, gomi o hiroimashita.","id":"Kami berkumpul pagi-pagi dan memungut sampah."},
   {"jp":"海にはプラスチックのゴミがたくさんありました。","furigana":"うみにはプラスチックのゴミがたくさんありました。","romaji":"Umi ni wa purasuchikku no gomi ga takusan arimashita.","id":"Di pantai ada banyak sampah plastik."},
   {"jp":"ゴミは海の動物にとって危険です。","furigana":"ゴミはうみのどうぶつにとってきけんです。","romaji":"Gomi wa umi no doubutsu ni totte kiken desu.","id":"Sampah berbahaya bagi hewan laut."},
   {"jp":"みんなで協力して、たくさんのゴミを集めました。","furigana":"みんなできょうりょくして、たくさんのゴミをあつめました。","romaji":"Minna de kyouryoku shite, takusan no gomi o atsumemashita.","id":"Dengan kerja sama, kami mengumpulkan banyak sampah."},
   {"jp":"三時間後、海はとてもきれいになりました。","furigana":"さんじかんご、うみはとてもきれいになりました。","romaji":"San-jikan go, umi wa totemo kirei ni narimashita.","id":"Tiga jam kemudian, pantai jadi sangat bersih."},
   {"jp":"体は疲れましたが、心は気持ちよかったです。","furigana":"からだはつかれましたが、こころはきもちよかったです。","romaji":"Karada wa tsukaremashita ga, kokoro wa kimochi yokatta desu.","id":"Badan lelah, tapi hati terasa lega."},
   {"jp":"自分の行動が役に立って、嬉しかったです。","furigana":"じぶんのこうどうがやくにたって、うれしかったです。","romaji":"Jibun no koudou ga yaku ni tatte, ureshikatta desu.","id":"Aku senang tindakanku berguna."},
   {"jp":"環境を守ることはとても大切だと思いました。","furigana":"かんきょうをまもることはとてもたいせつだとおもいました。","romaji":"Kankyou o mamoru koto wa totemo taisetsu da to omoimashita.","id":"Aku merasa menjaga lingkungan itu sangat penting."},
   {"jp":"これからも、時々ボランティアに参加したいです。","furigana":"これからも、ときどきボランティアにさんかしたいです。","romaji":"Korekara mo, tokidoki borantia ni sanka shitai desu.","id":"Ke depan pun, aku ingin sesekali ikut kegiatan sukarela."},
   {"jp":"小さな行動が、大きな変化につながると信じています。","furigana":"ちいさなこうどうが、おおきなへんかにつながるとしんじています。","romaji":"Chiisa na koudou ga, ooki na henka ni tsunagaru to shinjite imasu.","id":"Aku percaya tindakan kecil bisa membawa perubahan besar."}
 ]'::jsonb,
 '[
   {"word":"ボランティア","reading":"ボランティア","romaji":"borantia","meaning":"sukarelawan/kegiatan sukarela"},
   {"word":"活動","reading":"かつどう","romaji":"katsudou","meaning":"kegiatan"},
   {"word":"参加","reading":"さんか","romaji":"sanka","meaning":"ikut serta"},
   {"word":"誘う","reading":"さそう","romaji":"sasou","meaning":"mengajak"},
   {"word":"掃除","reading":"そうじ","romaji":"souji","meaning":"membersihkan"},
   {"word":"集まる","reading":"あつまる","romaji":"atsumaru","meaning":"berkumpul"},
   {"word":"拾う","reading":"ひろう","romaji":"hirou","meaning":"memungut"},
   {"word":"プラスチック","reading":"プラスチック","romaji":"purasuchikku","meaning":"plastik"},
   {"word":"危険","reading":"きけん","romaji":"kiken","meaning":"berbahaya"},
   {"word":"協力","reading":"きょうりょく","romaji":"kyouryoku","meaning":"kerja sama"},
   {"word":"集める","reading":"あつめる","romaji":"atsumeru","meaning":"mengumpulkan"},
   {"word":"行動","reading":"こうどう","romaji":"koudou","meaning":"tindakan"},
   {"word":"環境","reading":"かんきょう","romaji":"kankyou","meaning":"lingkungan"},
   {"word":"守る","reading":"まもる","romaji":"mamoru","meaning":"menjaga/melindungi"},
   {"word":"変化","reading":"へんか","romaji":"henka","meaning":"perubahan"}
 ]'::jsonb,
 '[
   {"q":"Kegiatan sukarela apa yang diikuti penulis?","options":["Mengajar","Membersihkan pantai","Menanam pohon","Donor darah"],"answer":1,"explanation":"「海の掃除をしました」."},
   {"q":"Siapa yang mengajak penulis?","options":["Guru","Teman","Keluarga","Tetangga"],"answer":1,"explanation":"「友だちに誘われて」 = diajak teman."},
   {"q":"Jenis sampah apa yang banyak?","options":["Kertas","Plastik","Logam","Kaca"],"answer":1,"explanation":"「プラスチックのゴミがたくさん」."},
   {"q":"Sampah berbahaya bagi siapa?","options":["Manusia","Hewan laut","Tumbuhan","Tidak ada"],"answer":1,"explanation":"「海の動物にとって危険」."},
   {"q":"Setelah berapa lama pantai jadi bersih?","options":["Satu jam","Dua jam","Tiga jam","Lima jam"],"answer":2,"explanation":"「三時間後…きれいになりました」."},
   {"q":"Apa yang penulis rasa penting?","options":["Mencari uang","Menjaga lingkungan","Berolahraga","Berteman"],"answer":1,"explanation":"「環境を守ることは…大切」."}
 ]'::jsonb,
 false);
